<?phpnamespace App\Controller;use App\Entity\SysAdminOperation;use App\Entity\TypeUsageBien;use App\Form\TypeUsageBienType;use App\Repository\TypeUsageBienRepository;use DateTime;use DateTimeZone;use Exception;use Sensio\Bundle\FrameworkExtraBundle\Configuration\Security;use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;use Symfony\Component\HttpFoundation\Request;use Symfony\Component\HttpFoundation\Response;use Symfony\Component\Routing\Annotation\Route;class TypeUsageBienController extends AbstractController{    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/type-usage-biens", name="type_usage_bien_index", methods={"GET"})     * @param TypeUsageBienRepository $typeUsageBienRepository     * @return Response     */    public function index(TypeUsageBienRepository $typeUsageBienRepository): Response    {        return $this->render('type_usage_bien/index.html.twig', [            'type_usage_biens' => $typeUsageBienRepository->findAll(),        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/type-usage-biens/new", name="type_usage_bien_new", methods={"GET","POST"})     * @param Request $request     * @return Response     * @throws Exception     * @throws Exception     */    public function new(Request $request): Response    {        $typeUsageBien = new TypeUsageBien();        $form = $this->createForm(TypeUsageBienType::class, $typeUsageBien);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->persist($typeUsageBien);            $entityManager->flush();            $this->addFlash('success', 'Le type usage bien a été enregistré');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Enregistrement type usage bien')                ->setUserAffected($typeUsageBien->getName());            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();            return $this->redirectToRoute('type_usage_bien_index');        }        return $this->render('type_usage_bien/new.html.twig', [            'type_usage_bien' => $typeUsageBien,            'form' => $form->createView(),        ]);    }    /**     * @Route("/super-admin/type-usage-biens/{id}", name="type_usage_bien_show", methods={"GET"})     * @param TypeUsageBien $typeUsageBien     * @return Response     */    public function show(TypeUsageBien $typeUsageBien): Response    {        return $this->render('type_usage_bien/show.html.twig', [            'type_usage_bien' => $typeUsageBien,        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/type-usage-biens/{id}/edit", name="type_usage_bien_edit", methods={"GET","POST"})     * @param Request $request     * @param TypeUsageBien $typeUsageBien     * @return Response     * @throws Exception     * @throws Exception     */    public function edit(Request $request, TypeUsageBien $typeUsageBien): Response    {        $form = $this->createForm(TypeUsageBienType::class, $typeUsageBien);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $this->getDoctrine()->getManager()->flush();            $this->addFlash('success', 'Le type usage bien a été modifié');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Modification type usage bien')                ->setUserAffected($typeUsageBien->getName());            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();            return $this->redirectToRoute('type_usage_bien_index');        }        return $this->render('type_usage_bien/edit.html.twig', [            'type_usage_bien' => $typeUsageBien,            'form' => $form->createView(),        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/type-usage-biens/{id}", name="type_usage_bien_delete", methods={"DELETE"})     * @param Request $request     * @param TypeUsageBien $typeUsageBien     * @return Response     * @throws Exception     */    public function delete(Request $request, TypeUsageBien $typeUsageBien): Response    {        if ($this->isCsrfTokenValid('delete' . $typeUsageBien->getId(), $request->request->get('_token'))) {            $this->getDoctrine()->getManager()->remove($typeUsageBien);            $this->getDoctrine()->getManager()->flush();            $this->addFlash('success', 'Le type usage bien a été supprimé');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Suppression type usage bien')                ->setUserAffected($typeUsageBien->getName());            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();        }        return $this->redirectToRoute('type_usage_bien_index');    }}